#include <stdio.h>
#include <limits.h>

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int N; scanf("%d", &N);
        int H[505]; int K[505];
        int maxH = 0;
        for (int i = 0; i < N; ++i) { scanf("%d", &H[i]); if (H[i] > maxH) maxH = H[i]; }
        for (int i = 0; i < N; ++i) scanf("%d", &K[i]);
        int maxNeed = 2 * maxH;
        const int INF = INT_MAX/4;
        int dp[1005];
        for (int i = 0; i <= maxNeed; ++i) dp[i] = INF;
        dp[0] = 0;
        for (int i = 0; i < N; ++i) {
            int coin = K[i];
            for (int v = coin; v <= maxNeed; ++v) {
                if (dp[v-coin] + 1 < dp[v]) dp[v] = dp[v-coin] + 1;
            }
        }
        long long total = 0;
        int possible = 1;
        for (int i = 0; i < N; ++i) {
            int need = 2 * H[i];
            if (dp[need] == INF) { possible = 0; break; }
            total += dp[need];
        }
        if (!possible) printf("-1\n");
        else printf("%lld\n", total);
    }
    return 0;
}

