int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        vector<int> H(N), K(N);
        int maxH=0;
        for(int &x:H){cin>>x; maxH=max(maxH,x);}        
        for(int &x:K) cin>>x;
        int maxNeed = 2*maxH;
        const int INF = 1e9;
        vector<int> dp(maxNeed+1, INF);
        dp[0]=0;
        for(int coin:K){
            for(int v=coin; v<=maxNeed; ++v){
                dp[v]=min(dp[v], dp[v-coin]+1);
            }
        }
        long long ans=0; bool ok=true;
        for(int h:H){
            int need=2*h;
            if(dp[need]==INF){ok=false; break;}
            ans+=dp[need];
        }
        if(!ok) cout<<-1<<"\n";
        else cout<<ans<<"\n";
    }
    return 0;
}

