import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            int[] H = new int[N];
            int[] K = new int[N];
            st = new StringTokenizer(br.readLine());
            int maxH = 0;
            for (int i = 0; i < N; i++) {
                H[i] = Integer.parseInt(st.nextToken());
                if (H[i] > maxH) maxH = H[i];
            }
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) K[i] = Integer.parseInt(st.nextToken());
            int maxNeed = 2 * maxH;
            final int INF = 1_000_000_000;
            int[] dp = new int[maxNeed + 1];
            Arrays.fill(dp, INF);
            dp[0] = 0;
            for (int coin : K) {
                for (int v = coin; v <= maxNeed; v++) {
                    if (dp[v - coin] + 1 < dp[v]) dp[v] = dp[v - coin] + 1;
                }
            }
            long total = 0;
            boolean possible = true;
            for (int h : H) {
                int need = 2 * h;
                if (dp[need] == INF) { possible = false; break; }
                total += dp[need];
            }
            out.append(possible ? total : -1).append('\n');
        }
        System.out.print(out.toString());
    }
}

